package com.enterprise.samlsp.service;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.*;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;

import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.StringReader;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;

@Service
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";

    public String decodeBase64Response(String encodedResponse) {
        byte[] decodedBytes = Base64.getDecoder().decode(encodedResponse);
        return new String(decodedBytes, StandardCharsets.UTF_8);
    }

    public Document parseXml(String xml) throws ParserConfigurationException, SAXException, IOException {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Security: Prevent XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(xml));
        return builder.parse(inputSource);
    }

    public SamlUserAttributes extractAssertionAttributes(Document document) throws SamlProcessingException {
        SamlUserAttributes userAttributes = new SamlUserAttributes();

        // Validate response status
        validateResponseStatus(document);

        // Extract Issuer
        NodeList issuerNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            userAttributes.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract Assertion
        NodeList assertionNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertionNodes.getLength() == 0) {
            throw new SamlProcessingException("No SAML Assertion found in the response");
        }

        Element assertion = (Element) assertionNodes.item(0);

        // Extract NameID
        extractNameId(assertion, userAttributes);

        // Extract Conditions and validate
        validateConditions(assertion);

        // Extract AuthnStatement
        extractAuthnStatement(assertion, userAttributes);

        // Extract AttributeStatement
        extractAttributeStatement(assertion, userAttributes);

        logger.info("Successfully extracted SAML attributes for user: {}", userAttributes.getNameId());
        return userAttributes;
    }

    private void validateResponseStatus(Document document) throws SamlProcessingException {
        NodeList statusCodeNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() > 0) {
            Element statusCode = (Element) statusCodeNodes.item(0);
            String statusValue = statusCode.getAttribute("Value");
            if (statusValue != null && !statusValue.contains("Success")) {
                throw new SamlProcessingException("SAML Response status is not Success: " + statusValue);
            }
        }
    }

    private void extractNameId(Element assertion, SamlUserAttributes userAttributes) throws SamlProcessingException {
        NodeList subjectNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() > 0) {
            Element subject = (Element) subjectNodes.item(0);
            NodeList nameIdNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
            if (nameIdNodes.getLength() > 0) {
                userAttributes.setNameId(nameIdNodes.item(0).getTextContent().trim());
            }

            // Extract SubjectConfirmation and validate
            NodeList subjectConfirmationDataNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmationData");
            if (subjectConfirmationDataNodes.getLength() > 0) {
                Element confirmationData = (Element) subjectConfirmationDataNodes.item(0);
                String notOnOrAfter = confirmationData.getAttribute("NotOnOrAfter");
                if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                    Instant expiry = Instant.parse(notOnOrAfter);
                    if (Instant.now().isAfter(expiry)) {
                        throw new SamlProcessingException("SAML Subject confirmation has expired");
                    }
                }
            }
        }

        if (userAttributes.getNameId() == null || userAttributes.getNameId().isEmpty()) {
            throw new SamlProcessingException("NameID not found in SAML Assertion");
        }
    }

    private void validateConditions(Element assertion) throws SamlProcessingException {
        NodeList conditionsNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditions = (Element) conditionsNodes.item(0);

            String notBefore = conditions.getAttribute("NotBefore");
            String notOnOrAfter = conditions.getAttribute("NotOnOrAfter");

            Instant now = Instant.now();
            // Allow 5 minutes clock skew
            long clockSkewSeconds = 300;

            if (notBefore != null && !notBefore.isEmpty()) {
                Instant notBeforeInstant = Instant.parse(notBefore);
                if (now.plusSeconds(clockSkewSeconds).isBefore(notBeforeInstant)) {
                    throw new SamlProcessingException("SAML Assertion is not yet valid (NotBefore condition)");
                }
            }

            if (notOnOrAfter != null && !notOnOrAfter.isEmpty()) {
                Instant notOnOrAfterInstant = Instant.parse(notOnOrAfter);
                if (now.minusSeconds(clockSkewSeconds).isAfter(notOnOrAfterInstant)) {
                    throw new SamlProcessingException("SAML Assertion has expired (NotOnOrAfter condition)");
                }
            }
        }
    }

    private void extractAuthnStatement(Element assertion, SamlUserAttributes userAttributes) {
        NodeList authnStatementNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);

            String authnInstant = authnStatement.getAttribute("AuthnInstant");
            if (authnInstant != null && !authnInstant.isEmpty()) {
                userAttributes.setAuthenticationInstant(Instant.parse(authnInstant));
            }

            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            if (sessionIndex != null && !sessionIndex.isEmpty()) {
                userAttributes.setSessionIndex(sessionIndex);
            }

            String sessionNotOnOrAfter = authnStatement.getAttribute("SessionNotOnOrAfter");
            if (sessionNotOnOrAfter != null && !sessionNotOnOrAfter.isEmpty()) {
                userAttributes.setSessionNotOnOrAfter(Instant.parse(sessionNotOnOrAfter));
            }
        }
    }

    private void extractAttributeStatement(Element assertion, SamlUserAttributes userAttributes) {
        NodeList attributeStatementNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        if (attributeStatementNodes.getLength() > 0) {
            Element attributeStatement = (Element) attributeStatementNodes.item(0);
            NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

            for (int i = 0; i < attributeNodes.getLength(); i++) {
                Element attribute = (Element) attributeNodes.item(i);
                String attributeName = attribute.getAttribute("Name");
                String friendlyName = attribute.getAttribute("FriendlyName");

                NodeList attributeValueNodes = attribute.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
                if (attributeValueNodes.getLength() > 0) {
                    String attributeValue = attributeValueNodes.item(0).getTextContent().trim();

                    // Store by Name
                    if (attributeName != null && !attributeName.isEmpty()) {
                        userAttributes.addAttribute(attributeName, attributeValue);
                    }

                    // Also store by FriendlyName for convenience
                    if (friendlyName != null && !friendlyName.isEmpty()) {
                        userAttributes.addAttribute(friendlyName, attributeValue);
                    }
                }
            }
        }
    }
}

