package com.enterprise.samlsp.security;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;

import java.util.Collection;
import java.util.Collections;
import java.util.List;
import java.util.stream.Collectors;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String principal;
    private final SamlUserAttributes samlUserAttributes;

    public SamlAuthenticationToken(SamlUserAttributes samlUserAttributes) {
        super(deriveAuthorities(samlUserAttributes));
        this.principal = samlUserAttributes.getNameId();
        this.samlUserAttributes = samlUserAttributes;
        setAuthenticated(true);
    }

    private static Collection<? extends GrantedAuthority> deriveAuthorities(SamlUserAttributes attrs) {
        String roles = attrs.getAttribute("roles");
        if (roles == null) {
            roles = attrs.getAttribute("http://schemas.xmlsoap.org/claims/Group");
        }
        if (roles != null && !roles.isEmpty()) {
            List<SimpleGrantedAuthority> authorities = List.of(roles.split(",")).stream()
                    .map(String::trim)
                    .map(role -> new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()))
                    .collect(Collectors.toList());
            return authorities;
        }
        return Collections.singletonList(new SimpleGrantedAuthority("ROLE_USER"));
    }

    @Override
    public Object getCredentials() {
        return null;
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public SamlUserAttributes getSamlUserAttributes() {
        return samlUserAttributes;
    }
}

